Based on the reference materials and detailed specifications, here's the complete implementation of the `delete_inactive_users` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return 1; // Connection failed
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return 1; // Transaction start failed
  }

  // 3. Delete users with last_login < 2025-01-01 using where condition
  auto delete_result = (sqlgen::delete_from<User> | sqlgen::where_("last_login"_c < "2025-01-01"))(conn);
  if (!delete_result) {
    return 1; // Delete operation failed
  }

  // 4. Commit the transaction and return the result
  auto commit_result = conn->commit();
  if (commit_result) {
    return 0; // Success
  } else {
    return 1; // Commit failed
  }
}

} // namespace delete_inactive_users
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Transaction Management**: 
   - Begins transaction with `conn->begin_transaction()`
   - Commits transaction with `conn->commit()`
3. **Delete Operation**: 
   - Uses `sqlgen::delete_from<User>` template
   - Applies where condition with `sqlgen::where_("last_login"_c < "2025-01-01")`
   - Uses the pipe operator `|` to combine delete_from with where condition
4. **Date Comparison**: Uses `"last_login"_c < "2025-01-01"` to filter users who haven't logged in since 2025-01-01
5. **Error Handling**: Properly checks results at each step and returns appropriate exit codes

