#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return {}; // Return empty vector on connection error
    }
    auto conn = *conn_result;

    // Build the query using sqlgen
    auto query = sqlgen::select_from<Employee, "e1">(
        "name"_t1 | sqlgen::as<"employee">,
        "name"_t2 | sqlgen::as<"manager">
    )
    | sqlgen::left_join<Employee, "e2">("manager_id"_t1 == "emp_id"_t2)
    | sqlgen::to<std::vector<EmployeeManager>>;

    // Execute the query
    auto result = query(conn);
    if (!result) {
        return {}; // Return empty vector on query error
    }

    return *result;
}

}  // namespace query_employee_hierarchy
```

## Explanation of the Implementation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Query Construction**: 
   - Starts with `sqlgen::select_from<Employee, "e1">` to select from the Employee table with alias "e1"
   - Selects two fields: 
     - `"name"_t1 | sqlgen::as<"employee">` - employee name from table e1
     - `"name"_t2 | sqlgen::as<"manager">` - manager name from table e2
   - Uses `sqlgen::left_join<Employee, "e2">` to perform a LEFT JOIN with the Employee table aliased as "e2"
   - Specifies the join condition: `"manager_id"_t1 == "emp_id"_t2`
   - Uses `sqlgen::to<std::vector<EmployeeManager>>` to map results to the target struct

3. **Query Execution**: Executes the query using the connection and handles potential errors by returning an empty vector on failure.

4. **Result Mapping**: The results are automatically mapped to `std::vector<EmployeeManager>` using the field aliases ("employee" and "manager") that match the struct field names.

This implementation follows the sqlgen principles of using the pipe operator (`|`) to chain operations and leverages the library's type-safe query building capabilities as demonstrated in the reference materials.

