 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {}; // Return empty vector on connection failure
  }
  auto conn = conn_result.value();

  // 2. Use sqlgen update API with string operations to replace "foo" with "bar"
  // Update all notes by replacing "foo" with "bar" in the content field
  auto update_result = (update<Note>("content"_c.set(replace("content"_c, "foo", "bar"))) | where(true))(conn);
  if (!update_result) {
    return {}; // Return empty vector on update failure
  }

  // 3. Read the updated data back
  auto read_result = read<std::vector<Note>>(conn);
  if (!read_result) {
    return {}; // Return empty vector on read failure
  }

  // 4. Transform the results to match the UpdatedNote structure
  std::vector<UpdatedNote> updated_notes;
  for (const auto& note : read_result.value()) {
    updated_notes.push_back(UpdatedNote{
        .note_id = note.note_id,
        .updated_content = note.content
    });
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
