  if (!create_parent_result) {
    return false; // Failed to create parent table
  }

  auto create_child_result = sqlgen::create_table<Child>(conn);
  if (!create_child_result) {
    return false; // Failed to create child table
  }

  // Insert parent and child records
  Parent parent{1, "Test Parent"};
  Child child{1, 1, "Test Child Note"};

  auto insert_parent_result = sqlgen::insert(parent)(conn);
  if (!insert_parent_result) {
    return false; // Failed to insert parent
  }

  auto insert_child_result = sqlgen::insert(child)(conn);
  if (!insert_child_result) {
    return false; // Failed to insert child
  }

  // Verify child exists before deletion
  auto read_child_before = sqlgen::read<std::vector<Child>>(conn);
  if (!read_child_before) {
    return false; // Read failed before deletion
