JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // Create tables
  sqlgen::create_table<Department> | sqlgen::if_not_exists(conn).value();
  sqlgen::create_table<Employee> | sqlgen::if_not_exists(conn).value();

  // Insert data
  sqlgen::insert(depts)(conn).value();
  sqlgen::insert(emps)(conn).value();

  // Define join condition
  auto dept_col = sqlgen::col<"department_id", "d">;
  auto emp_col = sqlgen::col<"department_id", "e">;
  auto join_condition = dept_col == emp_col;

  // INNER JOIN: Employees with assigned departments
  auto inner_query = sqlgen::read<std::vector<JoinResult>> 
                     | sqlgen::inner_join<Department, Employee, "e">(join_condition);
  auto inner_results = inner_query(conn).value();

  // LEFT JOIN: All employees (including those without departments)
  auto left_query = sqlgen::read<std::vector<JoinResult>> 
                   | sqlgen::left_join<Department, Employee, "e">(join_condition);
  auto left_results = left_query(conn).value();

  // RIGHT JOIN: All departments (including those without employees)
  auto right_query = sqlgen::read<std::vector<JoinResult>> 
                   | sqlgen::right_join<Department, Employee, "e">(join_condition);
  auto right_results = right_query(conn).value();

  // FULL JOIN: All employees and departments
  auto full_query = sqlgen::read<std::vector<JoinResult>> 
                   | sqlgen::full_join<Department, Employee, "e">(join_condition);
  auto full_results = full_query(conn).value();

  // Build analysis results
  JoinAnalysis analysis;
  analysis.inner_join_results = std::move(inner_results);
  analysis.left_join_results = std::move(left_results);
  analysis.right_join_results = std::move(right_results);
  analysis.full_join_results = std::move(full_results);

  return analysis;
}
}  // namespace analyze_department_employees
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(":memory:")` to create an in-memory SQLite database connection.

2. **Table Creation**: Uses `sqlgen::create_table<T>` with `sqlgen::if_not_exists` to safely create Department and Employee tables.

3. **Data Insertion**: Uses `sqlgen::insert()` to insert the provided department and employee data into their respective tables.

4. **Join Operations**: Implements all four required join types using sqlgen's join functions:
   - `inner_join` for employees with assigned departments
   - `left_join` for all employees (including those without departments)
   - `right_join` for all departments (including those without employees)
   - `full_join` for the complete union of both tables

5. **Result Reading**: Uses `sqlgen::read<std::vector<JoinResult>>` to execute each join query and retrieve results in the specified format.

6. **Join Condition**: Defines a reusable join condition using department_id columns with proper table aliases ("d" for Department, "e" for Employee).

7. **Result Handling**: Properly moves the results into the `JoinAnalysis` struct and returns it.

This implementation demonstrates proficiency with sqlgen's functional programming style, proper use of the library's type-safe join operations, and comprehensive handling of different join scenarios as specified in the assessment objectives.

